    fn identToSymbol(self: *BaseSexer, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return symIdent;
        if (self.tryIdentAsKeyword(token, text)) |sym| return sym;
        return symIdent;
    }

    fn tryIdentAsKeyword(self: *BaseSexer, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.stateStack.getLast();
        if (ruby.keywordAs(text)) |id| {
            const idIdx = @intFromEnum(id);
            const sym = keywordToSymbol[idIdx];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.lastMatchedId = @intCast(idIdx);
                return sym;
            }
            const fallback = keywordFallbackSymbol;
            if (fallback != 0 and getAction(state, fallback) != 0) {
                self.lastMatchedId = @intCast(idIdx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *BaseSexer) !Sexp {
        self.injectedToken = SYM_program_START;
        return self.doParse(SYM_program);
    }
};

// =============================================================================
// Sexer (sexp rewriter)
//
// Optional wrapper supplied by the @lang module. When `ruby.zig` exports a
// `pub const Sexer = struct { ... }` whose surface matches BaseSexer
// (`init(allocator, source) -> Self`, `deinit`, `parse{Start}() !Sexp`),
// the generated parser routes through it. Otherwise Sexer aliases
// BaseSexer directly and there is no behavioral change.
// =============================================================================

pub const Sexer = if (@hasDecl(ruby, "Sexer")) ruby.Sexer else BaseSexer;

// =============================================================================
// Top-level convenience helpers (one per start symbol)
// =============================================================================

/// Convenience: instantiate the (lang-extended) sexer and parse a whole
/// program. Caller owns `result.sexer` and must call `result.sexer.deinit()`
/// when done with the returned tree (the tree references arena-allocated
/// memory owned by the sexer).
pub fn parseProgram(allocator: std.mem.Allocator, source: []const u8) !struct { sexer: Sexer, sexp: Sexp } {
    var s = Sexer.init(allocator, source);
    errdefer s.deinit();
    const sexp = try s.parseProgram();
    return .{ .sexer = s, .sexp = sexp };
}

// Symbol IDs
const SYM_program: u16 = 3;
const SYM_program_START: u16 = 193;
const SYM_kw_not: u16 = 9;
const symIdent: u16 = 89;

// Mapping from ruby.KeywordId to grammar symbol IDs (computed at comptime)
const keywordToSymbol = blk: {
    var arr: [512]u16 = .{0} ** 512;
    if (@hasField(ruby.KeywordId, "NEWLINE")) arr[@intFromEnum(ruby.KeywordId.NEWLINE)] = 63;
    if (@hasField(ruby.KeywordId, "SEMICOLON")) arr[@intFromEnum(ruby.KeywordId.SEMICOLON)] = 64;
    if (@hasField(ruby.KeywordId, "IF_MOD")) arr[@intFromEnum(ruby.KeywordId.IF_MOD)] = 65;
    if (@hasField(ruby.KeywordId, "UNLESS_MOD")) arr[@intFromEnum(ruby.KeywordId.UNLESS_MOD)] = 66;
    if (@hasField(ruby.KeywordId, "WHILE_MOD")) arr[@intFromEnum(ruby.KeywordId.WHILE_MOD)] = 67;
    if (@hasField(ruby.KeywordId, "UNTIL_MOD")) arr[@intFromEnum(ruby.KeywordId.UNTIL_MOD)] = 68;
    if (@hasField(ruby.KeywordId, "RESCUE_MOD")) arr[@intFromEnum(ruby.KeywordId.RESCUE_MOD)] = 69;
    if (@hasField(ruby.KeywordId, "NOT_KW")) arr[@intFromEnum(ruby.KeywordId.NOT_KW)] = 70;
    if (@hasField(ruby.KeywordId, "OR_KW")) arr[@intFromEnum(ruby.KeywordId.OR_KW)] = 71;
    if (@hasField(ruby.KeywordId, "AND_KW")) arr[@intFromEnum(ruby.KeywordId.AND_KW)] = 72;
    if (@hasField(ruby.KeywordId, "ASSIGN")) arr[@intFromEnum(ruby.KeywordId.ASSIGN)] = 73;
    if (@hasField(ruby.KeywordId, "PLUS_EQ")) arr[@intFromEnum(ruby.KeywordId.PLUS_EQ)] = 74;
